mapper.select:
SELECT festival_id, description, place_id, name, address, latitude, longitude, image_url, view_count, review_count, avg_rating, rnum FROM ( SELECT a.*, ROWNUM AS rnum FROM ( SELECT f.festival_id, f.description, p.place_id, p.name, p.address, p.latitude, p.longitude, p.image_url, p.view_count, (SELECT COUNT(*) FROM review WHERE place_id = p.place_id AND UPPER(status) = 'DISPLAY') AS review_count, (SELECT NVL(ROUND(AVG(rating), 1), 0) FROM review WHERE place_id = p.place_id AND UPPER(status) = 'DISPLAY') AS avg_rating, (6371 * acos( cos(#{lat, jdbcType=DOUBLE} * 3.14159 / 180) * cos(p.latitude * 3.14159 / 180) * cos((p.longitude * 3.14159 / 180) - (#{lng, jdbcType=DOUBLE} * 3.14159 / 180)) + sin(#{lat, jdbcType=DOUBLE} * 3.14159 / 180) * sin(p.latitude * 3.14159 / 180) )) AS distance FROM festival f JOIN place p ON f.festival_id = p.place_id WHERE f.status != 'ENDED'
AND p.name LIKE '%' || #{keyword} || '%'
ORDER BY distance ASC ) a WHERE a.distance <= #{radius, jdbcType=DOUBLE}
AND a.avg_rating >= #{minRating, jdbcType=DOUBLE}
AND ROWNUM <= #{end, jdbcType=INTEGER}
AND p.address LIKE '%' || #{province} || '%'
AND p.address LIKE '%' || #{district} || '%'
) WHERE rnum >= #{start, jdbcType=INTEGER}

SELECT festival_id, place_id, name, latitude, longitude, image_url, avg_rating, review_count, view_count FROM ( SELECT f.festival_id, p.place_id, p.name, p.latitude, p.longitude, p.image_url, p.view_count, (SELECT COUNT(*) FROM review WHERE place_id = p.place_id AND UPPER(status) = 'DISPLAY') AS review_count, (SELECT NVL(ROUND(AVG(rating), 1), 0) FROM review WHERE place_id = p.place_id AND UPPER(status) = 'DISPLAY') AS avg_rating, (6371 * acos( cos(#{lat, jdbcType=DOUBLE} * 3.14159 / 180) * cos(p.latitude * 3.14159 / 180) * cos((p.longitude * 3.14159 / 180) - (#{lng, jdbcType=DOUBLE} * 3.14159 / 180)) + sin(#{lat, jdbcType=DOUBLE} * 3.14159 / 180) * sin(p.latitude * 3.14159 / 180) )) AS distance FROM festival f JOIN place p ON f.festival_id = p.place_id WHERE f.status != 'ENDED'
AND (p.name LIKE '%' || #{keyword} || '%')
AND p.address LIKE '%' || #{province} || '%'
AND p.address LIKE '%' || #{district} || '%'
) a
a.distance <= #{radius, jdbcType=DOUBLE}
AND a.avg_rating >= #{minRating, jdbcType=DOUBLE}
ORDER BY a.distance ASC

SELECT COUNT(*)
FROM favorite
WHERE user_id = #{userId}
AND place_id = #{placeId}

